class FenwickTree {
    private size: number;
    private tree: number[];

    constructor(size: number) {
        this.size = size;
        this.tree = new Array(size + 1).fill(0);
    }

    update(index: number, delta: number): void {
        while (index <= this.size) {
            this.tree[index] += delta;
            index += index & -index;
        }
    }

    query(index: number): number {
        let res = 0;
        while (index > 0) {
            res += this.tree[index];
            index -= index & -index;
        }
        return res;
    }

    rangeQuery(l: number, r: number): number {
        return this.query(r) - this.query(l - 1);
    }
}

function solve(nums: number[], queries: number[][]): number[] {
    function popcount(x: number): number {
        let count = 0;
        while (x) {
            x &= x - 1;
            count++;
        }
        return count;
    }

    function getDepth(x: number): number {
        let depth = 0;
        let current = x;
        while (current !== 1) {
            current = popcount(current);
            depth++;
        }
        return depth;
    }

    const n = nums.length;
    const maxDepth = 5;
    const ft = new Array(maxDepth + 1).fill(0).map(() => new FenwickTree(n));

    const currentValues = nums.slice();
    const depths = new Array(n);
    for (let i = 0; i < n; i++) {
        depths[i] = getDepth(currentValues[i]);
    }

    for (let i = 0; i < n; i++) {
        const d = depths[i];
        if (d <= maxDepth) {
            ft[d].update(i + 1, 1);
        }
    }

    const answer: number[] = [];

    for (const q of queries) {
        if (q[0] === 1) {
            const l = q[1];
            const r = q[2];
            const k = q[3];
            if (k > maxDepth) {
                answer.push(0);
                continue;
            }
            const res = ft[k].rangeQuery(l + 1, r + 1);
            answer.push(res);
        } else {
            const idx = q[1];
            const val = q[2];
            const oldVal = currentValues[idx];
            const oldDepth = getDepth(oldVal);
            const newDepth = getDepth(val);
            ft[oldDepth].update(idx + 1, -1);
            ft[newDepth].update(idx + 1, 1);
            currentValues[idx] = val;
        }
    }

    return answer;
}

